class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.size();
        int firstZero = -1;
        for (int i = 0; i < n; i++) {
            if (binary[i] == '0') {
                firstZero = i;
                break;
            }
        }
        if (firstZero == -1) return binary;
        string res = "";
        for (int i = 0; i < n; i++) {
            if (i == firstZero) res += '0';
            else res += '1';
        }
        return res;
    }
};

